(newValue, oldValue) => {
  if (areEqual(newValue, oldValue)) return
  if (modelValue.value === undefined) {
    index.value = undefined
    return
  }

  if (!props.free) {
    const idx = accordionItems.value.findIndex(
      (item) =>
        item.id ===
        (!isReadOnlyArray(modelValue.value) ? modelValue.value : modelValue.value?.[0])
    )

    if (idx !== -1) {
      if (index.value !== idx) {
        index.value = idx
      }
    } else {
      nextTick(() => {
        modelValue.value = undefined
      })
    }
  } else if (props.free) {
    if (isReadOnlyArray(modelValue.value)) {
      const idxes = modelValue.value
        .map((value) => accordionItems.value.findIndex((item) => item.id === value))
        .filter((index) => index !== -1)
      if (idxes.length > 0) {
        if (!areEqual(idxes, index.value)) {
          index.value = idxes
        }
      } else {
        nextTick(() => {
          modelValue.value = undefined
        })
      }
    } else {
      const newValue = accordionItems.value.findIndex((item) => item.id === modelValue.value)
      if (!areEqual(newValue, index.value)) {
        index.value = newValue
      }
    }
  }
}

setValues(newValue: number | number[]) {
    if (this.min > this.max) {
        return
    }
    if (Array.isArray(newValue)) {
        this.isRange = true
        const smallValue = typeof newValue[0] !== 'number' || isNaN(newValue[0])
            ? this.min
            : bound(newValue[0], this.min, this.max)
        const largeValue = typeof newValue[1] !== 'number' || isNaN(newValue[1])
            ? this.max
            : bound(newValue[1], this.min, this.max)
        // premature update will be triggered and end up with circular
        // update, if value1 and value2 are updated one by one
        this.internal = {
            value1: this.isThumbReversed ? largeValue : smallValue,
            value2: this.isThumbReversed ? smallValue : largeValue
        }
    } else {
        this.isRange = false
        this.internal = {
            value1: isNaN(newValue)
                ? this.min
                : bound(newValue, this.min, this.max),
            value2: undefined
        }
    }
}

