doOnChange() {
  const { _hue, _saturation, _value, _alpha, format } = this;

  if (this.enableAlpha) {
    switch (format) {
      case 'hsl':
        const hsl = hsv2hsl(_hue, _saturation / 100, _value / 100);
        this.value = `hsla(${ _hue }, ${ Math.round(hsl[1] * 100) }%, ${ Math.round(hsl[2] * 100) }%, ${ _alpha / 100})`;
        break;
      case 'hsv':
        this.value = `hsva(${ _hue }, ${ Math.round(_saturation) }%, ${ Math.round(_value) }%, ${ _alpha / 100})`;
        break;
      default:
        const { r, g, b } = hsv2rgb(_hue, _saturation, _value);
        this.value = `rgba(${r}, ${g}, ${b}, ${ _alpha / 100 })`;
    }
  } else {
    switch (format) {
      case 'hsl':
        const hsl = hsv2hsl(_hue, _saturation / 100, _value / 100);
        this.value = `hsl(${ _hue }, ${ Math.round(hsl[1] * 100) }%, ${ Math.round(hsl[2] * 100) }%)`;
        break;
      case 'hsv':
        this.value = `hsv(${ _hue }, ${ Math.round(_saturation) }%, ${ Math.round(_value) }%)`;
        break;
      case 'rgb':
        const { r, g, b } = hsv2rgb(_hue, _saturation, _value);
        this.value = `rgb(${r}, ${g}, ${b})`;
        break;
      default:
        this.value = toHex(hsv2rgb(_hue, _saturation, _value));
    }
  }
}

handleKeyControl(keyCode) {
  const mapping = {
    'year': {
      38: -4, 40: 4, 37: -1, 39: 1, offset: (date, step) => date.setFullYear(date.getFullYear() + step)
    },
    'month': {
      38: -4, 40: 4, 37: -1, 39: 1, offset: (date, step) => date.setMonth(date.getMonth() + step)
    },
    'week': {
      38: -1, 40: 1, 37: -1, 39: 1, offset: (date, step) => date.setDate(date.getDate() + step * 7)
    },
    'day': {
      38: -7, 40: 7, 37: -1, 39: 1, offset: (date, step) => date.setDate(date.getDate() + step)
    }
  };
  const mode = this.selectionMode;
  const year = 3.1536e10;
  const now = this.date.getTime();
  const newDate = new Date(this.date.getTime());
  while (Math.abs(now - newDate.getTime()) <= year) {
    const map = mapping[mode];
    map.offset(newDate, map[keyCode]);
    if (typeof this.disabledDate === 'function' && this.disabledDate(newDate)) {
      continue;
    }
    this.date = newDate;
    this.$emit('pick', newDate, true);
    break;
  }
}

getThemeCluster(theme) {
  const tintColor = (color, tint) => {
    let red = parseInt(color.slice(0, 2), 16);
    let green = parseInt(color.slice(2, 4), 16);
    let blue = parseInt(color.slice(4, 6), 16);

    if (tint === 0) { // when primary color is in its rgb space
      return [red, green, blue].join(',');
    } else {
      red += Math.round(tint * (255 - red));
      green += Math.round(tint * (255 - green));
      blue += Math.round(tint * (255 - blue));

      red = red.toString(16);
      green = green.toString(16);
      blue = blue.toString(16);

      return `#${ red }${ green }${ blue }`;
    }
  };

  const shadeColor = (color, shade) => {
    let red = parseInt(color.slice(0, 2), 16);
    let green = parseInt(color.slice(2, 4), 16);
    let blue = parseInt(color.slice(4, 6), 16);

    red = Math.round((1 - shade) * red);
    green = Math.round((1 - shade) * green);
    blue = Math.round((1 - shade) * blue);

    red = red.toString(16);
    green = green.toString(16);
    blue = blue.toString(16);

    return `#${ red }${ green }${ blue }`;
  };

  const clusters = [theme];
  for (let i = 0; i <= 9; i++) {
    clusters.push(tintColor(theme, Number((i / 10).toFixed(2))));
  }
  clusters.push(shadeColor(theme, 0.1));
  return clusters;
}

updateDocStyle(e, cb) {
  const val = e.global['$--color-primary'] || ORIGINAL_THEME;
  const oldVal = this.theme;
  const getHandler = (variable, id) => {
    return () => {
      let newStyle = this.updateStyle(this[variable], ORIGINAL_THEME, val);
      updateDomHeadStyle(id, newStyle);
      this.asyncCb && cb();
    };
  };
  const docsHandler = getHandler('docs', 'docs-style');
  if (!this.docs) {
    const links = [].filter.call(document.querySelectorAll('link'), link => {
      return /docs\..+\.css/.test(link.href || '');
    });
    if (links[0]) {
      this.getCSSString(links[0].href, docsHandler, 'docs');
    } else {
      this.asyncCb = false;
    }
  } else {
    docsHandler();
  }
  const styles = [].slice.call(document.querySelectorAll('style'))
    .filter(style => {
      const text = style.innerText;
      return new RegExp(oldVal, 'i').test(text) && !/Chalk Variables/.test(text);
    });
  styles.forEach(style => {
    const { innerText } = style;
    if (typeof innerText !== 'string') return;
    style.innerText = this.updateStyle(innerText, oldVal, val);
  });
  this.theme = val;
  !this.asyncCb && cb();
}

