onExpand(node) {
    if (!node.children) {
        this.loading = true;

        setTimeout(() => {
            let lazyNode = { ...node };

            lazyNode.children = [
                {
                    data: {
                        name: lazyNode.data.name + ' - 0',
                        size: Math.floor(Math.random() * 1000) + 1 + 'kb',
                        type: 'File'
                    }
                },
                {
                    data: {
                        name: lazyNode.data.name + ' - 1',
                        size: Math.floor(Math.random() * 1000) + 1 + 'kb',
                        type: 'File'
                    }
                }
            ];

            let nodes = this.nodes.map((n) => {
                if (n.key === node.key) {
                    n = lazyNode;
                }

                return n;
            });

            this.loading = false;
            this.nodes = nodes;
        }, 250);
    }
